4602   if (!II || !II->hasOneUse())
4603     return false;
4604 
4605   const auto IsValidOrUmaxCmp = [&]() {
4606     // or === umax for i1
4607     if (CmpVal->getBitWidth() == 1)
4608       return true;
4609 
4610     // Cases a and e
4611     bool IsEquality =
4612         (CmpVal->isZero() || CmpVal->isOne()) && ICmpInst::isEquality(Pred);
4613     // Case c
4614     bool IsPositive = CmpVal->isAllOnes() && Pred == ICmpInst::ICMP_SGT;
4615     // Cases b, d, and f
4616     bool IsNegative = (CmpVal->isZero() || CmpVal->isOne() || *CmpVal == 2) &&
4617                       Pred == ICmpInst::ICMP_SLT;
4618     return IsEquality || IsPositive || IsNegative;
4619   };
4620 
4621   const auto IsValidAndUminCmp = [&]() {
4622     // and === umin for i1
4623     if (CmpVal->getBitWidth() == 1)
4624       return true;
4625 
4626     const auto LeadingOnes = CmpVal->countl_one();
4627 
4628     // Cases g and k
4629     bool IsEquality =
4630         (CmpVal->isAllOnes() || LeadingOnes + 1 == CmpVal->getBitWidth()) &&
4631         ICmpInst::isEquality(Pred);
4632     // Case h
4633     bool IsNegative = CmpVal->isZero() && Pred == ICmpInst::ICMP_SLT;
4634     // Cases i, j, and l
4635     bool IsPositive =
4636         // if the number has at least N - 2 leading ones
4637         // and the two LSBs are:
4638         //   - 1 x 1 -> -1
4639         //   - 1 x 0 -> -2
4640         //   - 0 x 1 -> -3
4641         LeadingOnes + 2 >= CmpVal->getBitWidth() &&
4642         ((*CmpVal)[0] || (*CmpVal)[1]) && Pred == ICmpInst::ICMP_SGT;
4643     return IsEquality || IsNegative || IsPositive;
4644   };
