4710 /// Returns true if this ShuffleVectorInst eventually feeds into a
4711 /// vector reduction intrinsic (e.g., vector_reduce_add) by only following
4712 /// chains of shuffles and binary operators (in any combination/order).
4713 /// The search does not go deeper than the given Depth.
4714 static bool feedsIntoVectorReduction(ShuffleVectorInst *SVI) {
4715   constexpr unsigned MaxVisited = 32;
4716   SmallPtrSet<Instruction *, 8> Visited;
4717   SmallVector<Instruction *, 4> WorkList;
4718   bool FoundReduction = false;
4719 
4720   WorkList.push_back(SVI);
4721   while (!WorkList.empty()) {
4722     Instruction *I = WorkList.pop_back_val();
4723     for (User *U : I->users()) {
4724       auto *UI = cast<Instruction>(U);
4725       if (!UI || !Visited.insert(UI).second)
4726         continue;
4727       if (Visited.size() > MaxVisited)
4728         return false;
4729       if (auto *II = dyn_cast<IntrinsicInst>(UI)) {
4730         // More than one reduction reached
4731         if (FoundReduction)
4732           return false;
4733         switch (II->getIntrinsicID()) {
4734         case Intrinsic::vector_reduce_add:
4735         case Intrinsic::vector_reduce_mul:
4736         case Intrinsic::vector_reduce_and:
4737         case Intrinsic::vector_reduce_or:
4738         case Intrinsic::vector_reduce_xor:
4739         case Intrinsic::vector_reduce_smin:
4740         case Intrinsic::vector_reduce_smax:
4741         case Intrinsic::vector_reduce_umin:
4742         case Intrinsic::vector_reduce_umax:
4743           FoundReduction = true;
4744           continue;
4745         default:
4746           return false;
4747         }
4748       }
4749 
4750       if (!isa<BinaryOperator>(UI) && !isa<ShuffleVectorInst>(UI))
4751         return false;
4752 
4753       WorkList.emplace_back(UI);
4754     }
4755   }
4756   return FoundReduction;
4757 }
